+// ============================================================================
+// SQL Generation Helpers
+// ============================================================================
+
+/// Convert AggregateType to SQL string.
+fn aggTypeStr(agg_type: AggregateType) []const u8 {
+    return switch (agg_type) {
+        .count => "COUNT",
+        .sum => "SUM",
+        .avg => "AVG",
+        .min => "MIN",
+        .max => "MAX",
+        .stddev => "STDDEV",
+        .stddev_pop => "STDDEV_POP",
+        .variance => "VARIANCE",
+        .var_pop => "VAR_POP",
+        .median => "MEDIAN",
+        .percentile => "PERCENTILE",
+        .count_distinct => "COUNT_DISTINCT",
+        .first => "FIRST",
+        .last => "LAST",
+        .group_concat => "GROUP_CONCAT",
+        .array_agg => "ARRAY_AGG",
+        .string_agg => "STRING_AGG",
+        .bit_and => "BIT_AND",
+        .bit_or => "BIT_OR",
+        .bit_xor => "BIT_XOR",
+        .bool_and => "BOOL_AND",
+        .bool_or => "BOOL_OR",
+        .any_value => "ANY_VALUE",
+        .corr => "CORR",
+        .covar_pop => "COVAR_POP",
+        .covar_samp => "COVAR_SAMP",
+        .regr_avgx => "REGR_AVGX",
+        .regr_avgy => "REGR_AVGY",
+        .regr_count => "REGR_COUNT",
+        .regr_intercept => "REGR_INTERCEPT",
+        .regr_r2 => "REGR_R2",
+        .regr_slope => "REGR_SLOPE",
+        .regr_sxx => "REGR_SXX",
+        .regr_sxy => "REGR_SXY",
+        .regr_syy => "REGR_SYY",
+        .rollup_sum, .rollup_count, .rollup_avg, .rollup_min, .rollup_max => "ROLLUP",
+    };
+}
+
+/// Convert JoinType to SQL string.
+fn joinTypeStr(join_type: JoinType) []const u8 {
+    return switch (join_type) {
+        .inner => "INNER",
+        .left => "LEFT",
+        .right => "RIGHT",
+        .full => "FULL",
+        .cross => "CROSS",
+        .natural => "NATURAL",
+        .left_semi => "LEFT SEMI",
+        .left_anti => "LEFT ANTI",
+    };
+}
